    with link = "point.nl.Rotterdam-Centraal", railway = :station :single {
        # NL UTR
        track(:double, ar[:rot.yu, :rot + 0.5sw] << 2md << 2ms);
        track(
                ar[:rot + 0.49sw, :rot + 0.5sw] << 2.5md << 2ms >> 0.5mt
            --  ar[:rot + 0.5sw + 3dl, :rot + 0.5sw + 4dl]
