        );
        track(ar[:rot + 0.40sw, :rot + 0.5sw + 1dl] << 1.5md << 2ms << 0.5mt);

        # NL RTH
        track(:double, ar[:rot.yu, :rot + 0.5sw] << 1md << 1ms);
        track(ar[:rot + 0.49sw, :rot + 0.5sw + 2dl] << 1.5md << 1ms >> 0.5mt);
        track(ar[:rot + 0.49sw, :rot + 0.5sw + 3dl] << 0.5md << 1ms << 0.5mt);


        # NL ARD
        track(
